import{_ as t,o as a,c as r,ag as o}from"./chunks/framework.BYehg5q7.js";const u=JSON.parse('{"title":"JSON Export & Import","description":"","frontmatter":{},"headers":[],"relativePath":"guide/json-export-import.md","filePath":"guide/json-export-import.md","lastUpdated":1774518415000}'),i={name:"guide/json-export-import.md"};function s(l,e,n,d,p,c){return a(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="json-export-import" tabindex="-1">JSON Export &amp; Import <a class="header-anchor" href="#json-export-import" aria-label="Permalink to &quot;JSON Export &amp; Import&quot;">​</a></h1><p>getbased can export your data to JSON files and import them back. This is useful for backups, transferring data between devices or browsers, and sharing data between profiles.</p><h2 id="single-profile-export" tabindex="-1">Single-Profile Export <a class="header-anchor" href="#single-profile-export" aria-label="Permalink to &quot;Single-Profile Export&quot;">​</a></h2><ol><li>Scroll to the <strong>Data &amp; Notes</strong> section at the bottom of the dashboard</li><li>Click <strong>Export JSON</strong></li><li>A <code>.json</code> file is downloaded to your device</li></ol><p>The exported file includes everything for the current profile:</p><ul><li>All lab entries (every date, every marker, every value)</li><li>Notes</li><li>All 9 lifestyle context cards (diet, sleep, exercise, environment, etc.)</li><li>Health goals</li><li>Interpretive lens</li><li>Supplements</li><li>Biometrics (height, weight history, blood pressure history, pulse history)</li><li>Menstrual cycle data (if entered)</li><li>Genetics data (SNP results from DNA raw data import, if imported)</li><li>Context card change history (timestamped log of lifestyle changes)</li><li>Custom marker definitions</li><li>Chat history and conversation threads</li></ul><div class="tip custom-block"><p class="custom-block-title">Export before major changes</p><p>Before doing a large batch import or clearing data, export a JSON backup first. It&#39;s your safety net.</p></div><h2 id="per-client-export" tabindex="-1">Per-Client Export <a class="header-anchor" href="#per-client-export" aria-label="Permalink to &quot;Per-Client Export&quot;">​</a></h2><p>From the <strong>Client List</strong> modal, click the three-dot menu (⋮) next to any profile and select <strong>Export</strong>. This exports that specific client&#39;s data as a standalone JSON file — useful when you manage multiple profiles and need to share or back up one at a time.</p><h2 id="database-bundles" tabindex="-1">Database Bundles <a class="header-anchor" href="#database-bundles" aria-label="Permalink to &quot;Database Bundles&quot;">​</a></h2><p>For a full backup of everything across all profiles:</p><ul><li><strong>Client List</strong> → <strong>Export All</strong> button in the header</li><li><strong>Settings → Data</strong> → <strong>Export All Clients</strong></li></ul><p>This creates a database bundle containing every profile&#39;s data, chat history, threads, custom personalities, and settings. Use this for complete backups or migrating your entire getbased setup to a new browser or device.</p><h3 id="importing-a-database-bundle" tabindex="-1">Importing a Database Bundle <a class="header-anchor" href="#importing-a-database-bundle" aria-label="Permalink to &quot;Importing a Database Bundle&quot;">​</a></h3><p>Drop a database bundle onto the import drop zone. getbased detects it automatically and handles multi-profile merging:</p><ul><li>New profiles are created</li><li>Existing profiles are merged (lab entries by date, notes deduplicated)</li><li>Chat threads and custom personalities are carried over</li></ul><h2 id="importing-a-json-file" tabindex="-1">Importing a JSON File <a class="header-anchor" href="#importing-a-json-file" aria-label="Permalink to &quot;Importing a JSON File&quot;">​</a></h2><p>You import a JSON file the same way you import a PDF — by dropping it on the <strong>drop zone</strong> at the top of the dashboard.</p><p>getbased detects JSON files automatically and handles them differently from PDFs:</p><ul><li>Lab entries are <strong>merged by date</strong>: if the JSON has data for a date that already exists, the values are combined rather than overwritten</li><li>Notes are <strong>deduplicated</strong>: the same note won&#39;t appear twice</li><li>Context card fields (diet, sleep, environment, etc.) are <strong>overwritten</strong> by the imported values</li><li>Health goals are <strong>merged</strong> and deduplicated by text content</li></ul><p>No AI provider is needed to import a JSON file.</p><div class="warning custom-block"><p class="custom-block-title">Importing replaces context cards</p><p>If you import a JSON file that was exported from a different profile or device, the lifestyle context cards in your current profile will be overwritten by the imported values. Your lab entry data is safe — it merges rather than overwrites.</p></div><h2 id="transferring-between-devices" tabindex="-1">Transferring Between Devices <a class="header-anchor" href="#transferring-between-devices" aria-label="Permalink to &quot;Transferring Between Devices&quot;">​</a></h2><p>To move getbased data to a new computer or browser:</p><ol><li>Export JSON on the old device (or use a database bundle for all profiles)</li><li>Open getbased on the new device</li><li>Drop the JSON file onto the drop zone</li></ol><p>All your historical lab data, charts, and context will appear immediately.</p><h2 id="automatic-backups" tabindex="-1">Automatic Backups <a class="header-anchor" href="#automatic-backups" aria-label="Permalink to &quot;Automatic Backups&quot;">​</a></h2><p>getbased also creates automatic snapshots in the background as you add data. Up to 5 snapshots are kept, and you can restore any of them from <strong>Settings → Data → Backup &amp; Restore</strong>. These backups are stored in your browser&#39;s IndexedDB and do not leave your device.</p><p>For file-based automatic backups, see <a href="./folder-backup.html">Folder Backup</a>.</p>',29)])])}const m=t(i,[["render",s]]);export{u as __pageData,m as default};
